### Context-Based Auth

```typescript
// Gateway context
const server = new ApolloServer({
  gateway,
  context: async ({ req }) => {
    const token = req.headers.authorization;
    const user = await verifyToken(token);

    return { user, token };
  },
});

// Subgraph resolvers
const resolvers = {
  Query: {
    user(_, { id }, context) {
      if (!context.user) {
        throw new GraphQLError("Unauthorized", {
          extensions: { code: "UNAUTHENTICATED" },
