    .max(500, 'Bio must be at most 500 characters')
    .optional()
    .transform((val) => val?.trim()),
  website: z
    .string()
    .url('Invalid URL')
    .refine(
      (url) => {
        try {
          const parsed = new URL(url);
          return ['http:', 'https:'].includes(parsed.protocol);
        } catch {
          return false;
        }
      },
      { message: 'Only HTTP/HTTPS URLs are allowed' }
    )
    .optional(),
});

