## Keyboard Navigation

### Focus Management

```javascript
// Trap focus in modal
function trapFocus(element) {
  const focusableElements = element.querySelectorAll(
    'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
  );

  const firstFocusable = focusableElements[0];
  const lastFocusable = focusableElements[focusableElements.length - 1];

  element.addEventListener("keydown", (e) => {
    if (e.key === "Tab") {
      if (e.shiftKey && document.activeElement === firstFocusable) {
        e.preventDefault();
        lastFocusable.focus();
      } else if (!e.shiftKey && document.activeElement === lastFocusable) {
        e.preventDefault();
        firstFocusable.focus();
      }
    }

    if (e.key === "Escape") {
      closeModal();
    }
  });
}
```

### Custom Interactive Components

```javascript
// Accessible dropdown
class AccessibleDropdown {
  constructor(triggerElement) {
    this.trigger = triggerElement;
    this.menu = document.getElementById(
      this.trigger.getAttribute("aria-controls"),
    );
    this.isOpen = false;

    this.trigger.addEventListener("click", () => this.toggle());
    this.trigger.addEventListener("keydown", (e) => this.handleKeyDown(e));
  }

  toggle() {
    this.isOpen = !this.isOpen;
    this.trigger.setAttribute("aria-expanded", this.isOpen);
    this.menu.hidden = !this.isOpen;

    if (this.isOpen) {
      this.menu.querySelector('[role="menuitem"]')?.focus();
    }
  }

  handleKeyDown(e) {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      if (!this.isOpen) this.toggle();
      this.focusNextItem();
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      this.focusPreviousItem();
    } else if (e.key === "Escape") {
      this.toggle();
      this.trigger.focus();
    }
  }
}
```

